- (void)viewDidAppear:(BOOL)animated {  // 加载网页的动画
    [super viewDidAppear:animated];

    if (![self.title isEqual:@"隐私政策"] && ![self.title isEqual:@"服务协议"]) {
        UIImage *shareImage = [[[UIImage wb_imageNamed:@"more_button"] imageByResizeToSize:CGSizeMake(WBRpt(24), WBRpt(24)) contentMode:UIViewContentModeScaleAspectFit] imageWithRenderingMode:UIImageRenderingModeAlwaysOriginal];
        self.navigationItem.rightBarButtonItem = [[UIBarButtonItem alloc] initWithImage:shareImage style:UIBarButtonItemStylePlain target:self action:@selector(wakeupShareApp)];

        // 初始化动画视图
        self.animationView = [LOTAnimationView animationNamed:@"loadingAnimation.json"];
        self.animationView.layer.backgroundColor = RGBA(119, 119, 119, 0.7).CGColor;
        CGFloat screenWidth = [UIScreen mainScreen].bounds.size.width;
        CGFloat screenHeight = [UIScreen mainScreen].bounds.size.height;
        self.animationView.frame = CGRectMake(0, 0, screenWidth, screenHeight);
        [self.view addSubview:self.animationView];

        [self.animationView playWithCompletion:^(BOOL animationFinished) {
            if (animationFinished) {
                [self.animationView setLoopAnimation:YES];
                [self.animationView play];
            }
        }];
    }
}

