    // 确保在主线程上执行 UI 更新
    dispatch_async(dispatch_get_main_queue(), ^{
        [WBMineViewController shareApp];
    });
}

- (void)returnButtonClicked {
    // 离开当前网页后，重置为默认分享网页（分享落地页）
    [[NSNotificationCenter defaultCenter] postNotificationName:WBBackToOriginalShareUrlNotification object:nil];

    if (self.normalWebview) {
        [self.navigationController popViewControllerAnimated:YES];
        self.normalWebview = NO;    // 重置状态
    } else {
        // 处理返回按钮点击事件
        if (self.dismissBlock) {
            self.dismissBlock();
        } else {
            [self dismissViewControllerAnimated:YES completion:nil];
        }
    }
}

#pragma mark - WKNavigationDelegate

- (void)webView:(WKWebView *)webView didFinishNavigation:(WKNavigation *)navigation {
    NSString *script = [NSString stringWithFormat:@"const webox_client_token = '%@';", WBSettingManager.sharedManager.Token];
    // 注入客户端令牌
    [self.webView evaluateJavaScript:script completionHandler:^(id _Nullable res, NSError * _Nullable error) {
//        NSLog(@"%@", res);
        if (error) {
            NSLog(@"Error injecting client token: %@", error);
        } else {
            NSLog(@"Client Token Injected Successfully");
            // 获取网页标题
            NSString *getTitleScript = @"document.getElementsByTagName('title')[0].innerText";
            [self.webView evaluateJavaScript:getTitleScript completionHandler:^(id _Nullable titleResult, NSError * _Nullable titleError) {
                if (titleError) {
                    NSLog(@"Error evaluating JavaScript to get title: %@", titleError);
                } else {
                    NSString *pageTitle = titleResult;
                    NSLog(@"Page Title: %@", pageTitle);
                    [[NSNotificationCenter defaultCenter] postNotificationName:WBPresentShareContentNotification object:nil userInfo:@{@"shareTitle": pageTitle, @"shareDescription": @""}];
                    // 更新self.title属性
                    dispatch_async(dispatch_get_main_queue(), ^{
                        if (!self.title) {
                            self.title = pageTitle;
                            [self.animationView removeFromSuperview];   // 网页加载成功，关闭加载动画
                        } else {
                            self.normalWebview = YES;   // 旧版WebView界面
                        }
                    });
                }
            }];
        }
    }];
}

#pragma mark - WKUIDelegate
- (void)webView:(WKWebView *)webView runJavaScriptAlertPanelWithMessage:(NSString *)message initiatedByFrame:(WKFrameInfo *)frame completionHandler:(void (^)(void))completionHandler {
    UIAlertController *alertVC = [UIAlertController alertControllerWithTitle:nil message:message preferredStyle:UIAlertControllerStyleAlert];
    [alertVC addAction:[UIAlertAction actionWithTitle:@"ok" style:UIAlertActionStyleDefault handler:nil]];
    UIViewController *frontVC = [WBAppManager getUIApplicationRootViewController];
    frontVC = frontVC ?: frontVC.presentedViewController;
    [frontVC presentViewController:alertVC animated:true completion:nil];
    completionHandler();
}

#pragma mark - Lazy load

- (WKWebView *)webView {
    if (_webView == nil) {
        WKWebViewConfiguration *config = [[WKWebViewConfiguration alloc] init];
        WKPreferences *preferences = [[WKPreferences alloc] init];
        preferences.javaScriptEnabled = true;
        config.preferences = preferences;
        config.userContentController = [[WBWebViewContentController alloc] init];
        WKWebView *webView = [[WKWebView alloc] initWithFrame:CGRectZero configuration:config];
        webView.UIDelegate = self;
        webView.navigationDelegate = self;
        [self.view addSubview:webView];
        _webView = webView;
    }
    return _webView;
}

@end


