#import "WBWebViewContentController.h"

@implementation WBWebViewContentController

static NSString *kWBNotificationCenterPostMethodName = @"notifier";

- (instancetype)init {
    if (self = [super init]) {
        [self addScriptMessageHandler:self name:kWBNotificationCenterPostMethodName];
    }
    return self;
}

- (void)userContentController:(WKUserContentController *)userContentController didReceiveScriptMessage:(WKScriptMessage *)message {
    NSDictionary *params = message.body;
    if ([message.name isEqualToString:kWBNotificationCenterPostMethodName]) {
        NSString *notificationName = params[@"name"];
        id userInfo = params[@"userInfo"];
        NSParameterAssert([userInfo isKindOfClass:[NSDictionary class]]);
        [[NSNotificationCenter defaultCenter] postNotificationOnMainThreadWithName:notificationName object:self userInfo:userInfo];
    } else {
        NSParameterAssert(false);
    }
}

- (void)invokeCompletionJS:(NSString *)funcStr param:(BOOL)success webView:(WKWebView *)webView {
    NSString *invocation = [NSString stringWithFormat:@"(%@)", [funcStr stringByAppendingFormat:@"(%d)", success]];
    [webView evaluateJavaScript:invocation completionHandler:^(id _Nullable res, NSError * _Nullable error) {
        NSLog(@"%@", error);
    }];
}

@end



