#pragma mark - UITextFieldDelegate

- (void)textFieldDidBeginEditing:(UITextField *)textField {
    if (textField.tag == 234) {
        [textField becomeFirstResponder];
    } else {
        [textField becomeFirstResponder];
    }
}

- (BOOL)textField:(UITextField *)textField shouldChangeCharactersInRange:(NSRange)range replacementString:(NSString *)string {
    if (textField.tag == 234) {
        if (textField.text.length > 10 && ![string isEqualToString:@""]) {
            return NO;
        }
        return YES;
    } else {
        if (self.isPassWord == NO) {
            BOOL isPasteAction = string.length > 1;
            NSString *newText = [textField.text stringByReplacingCharactersInRange:range withString:string];
            if (newText.length > 6) {
                if (isPasteAction) {
                    [SVProgressHUD showErrorWithStatus:@"请输入6位数字验证码"];
                }
                return NO;
            }
            NSCharacterSet *nonDigitCharacterSet = [[NSCharacterSet decimalDigitCharacterSet] invertedSet];
            if ([newText rangeOfCharacterFromSet:nonDigitCharacterSet].location != NSNotFound) {
                if (isPasteAction) {
                    [SVProgressHUD showErrorWithStatus:@"请输入6位数字验证码"];
                }
                return NO;
            }
            return YES;
        } else {
            if (range.location >= 11) {
                if (![string isEqualToString:@"\n"]) {
                    [SVProgressHUD showErrorWithStatus:@"密码长度必须小于十一个字符"];
                }
                return false;
            }
            return true;
        }
    }
}

