        self.inputPhoneNumView.inputVerificationCode.text = nil;
        self.inputPhoneNumView.secSwitchBtn.hidden = YES;
        self.inputPhoneNumView.secSwitchBtn.userInteractionEnabled = NO;
        self.inputPhoneNumView.forgetBtn.hidden = YES;
        self.inputPhoneNumView.forgetBtn.userInteractionEnabled = NO;
