        [self.switchButton setTitle:@"手机号登录" forState:UIControlStateNormal];
        self.inputPhoneNumView.phoneTitleLabel.text = @"密码登录";
        self.inputPhoneNumView.phoneSubTitleLabel.hidden = YES;
