        self.inputPhoneNumView.secSwitchBtn.hidden = NO;
        self.inputPhoneNumView.forgetBtn.hidden = NO;
        self.inputPhoneNumView.forgetBtn.userInteractionEnabled = YES;
        self.inputPhoneNumView.secSwitchBtn.userInteractionEnabled = YES;
        NSMutableAttributedString *attrString = [
            [NSMutableAttributedString alloc] initWithString:@"请输入密码" attributes:
                @{
                    NSForegroundColorAttributeName:[UIColor grayColor],
                    NSFontAttributeName:[UIFont boldSystemFontOfSize:ZOOM(16)]
                }
