- (void)getCodeBtnClick {
    // 首次绑定
    if (![self IsPhoneNumber:self.inputPhoneNumView.inputPhone.text]) {
        [SVProgressHUD showErrorWithStatus:@"请输入正确手机号"];
        return;
    }

    self.inputPhoneNumView.verifyBtn.userInteractionEnabled = NO;
    [[WBNetworkManager defaultManager] getSmsCode:self.inputPhoneNumView.inputPhone.text reason:@"login" callback:^(id _Nullable json, NSError * _Nullable error) {
        if (error) {
            NSString *descriptionStr = error.userInfo[@"NSLocalizedDescription"];
            [SVProgressHUD showErrorWithStatus:descriptionStr];
            self.timerCount = 5;
            NSLog(@"save error:%@", error.userInfo);
        } else {
            NSLog(@"打印出的json为%@",json);
            self.timerCount = 59;
        }
        [self countdown];
        self.inputPhoneNumView.verifyBtn.userInteractionEnabled = YES;
    }];
}

- (void)loginBtnClick {
    if (!self.agreementCheckBoxButton.isSelected) {
        [SVProgressHUD showErrorWithStatus:@"请阅读并勾选协议"];
        return;
    }
    if (![self IsPhoneNumber:self.inputPhoneNumView.inputPhone.text]) {
        [SVProgressHUD showErrorWithStatus:@"请输入正确手机号"];
        return;
    }
    NSDictionary *post;
    if (self.isPassWord == YES) {
        if (self.inputPhoneNumView.inputVerificationCode.text.length < 6) {
            [SVProgressHUD showErrorWithStatus:@"密码小于6位"];
            return;
        } else {
            post = @{
                @"mobile":self.inputPhoneNumView.inputPhone.text,
                @"password":self.inputPhoneNumView.inputVerificationCode.text
            };
        }
    } else {
        if (![self IsVerificationCode:self.inputPhoneNumView.inputVerificationCode.text]) {
            [SVProgressHUD showErrorWithStatus:@"请输入6位数字验证码"];
            return;
        } else {
            post = @{
                @"mobile":self.inputPhoneNumView.inputPhone.text,
                @"code":self.inputPhoneNumView.inputVerificationCode.text
            };
        }
    }

    if (self.isLoginRequestInProgress) {
        return; // 如果登录请求正在进行中，不重复发起请求
    } else {
        self.isLoginRequestInProgress = YES; // 开始处理登录请求
    }

    [[WBNetworkManager defaultManager] getLogin:self.inputPhoneNumView.inputPhone.text getParams:post callback:^(id _Nullable json, NSError * _Nullable error) {
        if (error) {
            NSString *descriptionStr =  error.userInfo[@"NSLocalizedDescription"];
            [SVProgressHUD showErrorWithStatus:descriptionStr];
            self.isLoginRequestInProgress = NO;
            return;
        } else {
            // 广告、任务控制
            [[WBNetworkManager defaultManager] getAdsInfo:@"" callback:^(id  _Nullable adsJson, NSError * _Nullable error) {
                if (error) {
                    NSLog(@"获取广告控制信息失败：%@", error.localizedDescription);
                } else {
                    WBAdsHttpModel *adModel = [WBAdsHttpModel modelWithJSON:adsJson];
                    [WBSettingManager.sharedManager syncWithAds:adModel];
                }

                WBUserInfoHttpModel *model = [WBUserInfoHttpModel modelWithJSON:json];
                [WBSettingManager.sharedManager syncWithUserInfo:model];
                PostNotificationOnMainThread(WBAccountStatusChangedNotification, nil);
                [[NSNotificationCenter defaultCenter] postNotificationName:WBLoginSuccessNotification object:nil];

                if (self.isPassWord == YES) { // 密码登录
                    [self dismissViewControllerAnimated:YES completion:nil];
                    [[WBActionRequestManager sharedManager] requestReportEventWithType:WBActionRequestEventTypeUserLogined defaultHandler:nil];
                } else {  // 手机号登录
                    if (WBSettingManager.sharedManager.HasPassword) {
                        [self dismissViewControllerAnimated:YES completion:nil];
                        [[WBActionRequestManager sharedManager] requestReportEventWithType:WBActionRequestEventTypeUserLogined defaultHandler:nil];
                    } else {
                        WBSettingPasswordViewController *passwordVC = [[WBSettingPasswordViewController alloc] init];
                        passwordVC.skipHidden = @"2";
                        passwordVC.delegate = self;
                        passwordVC.modalPresentationStyle = UIModalPresentationFullScreen;
                        [self presentViewController:passwordVC animated:YES completion:nil];
                    }
                }
                self.isLoginRequestInProgress = NO;
            }];
        }
    }];
}

- (void)forgetBtnClick {
    WBForgotPassWordViewController *forgetVC = [[WBForgotPassWordViewController alloc] init];
    forgetVC.modalPresentationStyle = UIModalPresentationFullScreen;
    forgetVC.delegate = self;
    [self presentViewController:forgetVC animated:YES completion:nil];
}

- (void)countdown {
    __block int time = (int)self.timerCount;
    __block UIButton *verifybutton = self.inputPhoneNumView.verifyBtn;
    verifybutton.enabled = NO;
    dispatch_queue_t queue = dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_DEFAULT, 0);
    dispatch_source_t _timer = dispatch_source_create(DISPATCH_SOURCE_TYPE_TIMER, 0, 0,queue);
    dispatch_source_set_timer(_timer,dispatch_walltime(NULL, 0),1.0*NSEC_PER_SEC, 0); //每秒执行
    dispatch_source_set_event_handler(_timer, ^{
        if (time <= 0) { //倒计时结束，关闭
            dispatch_source_cancel(_timer);
            dispatch_async(dispatch_get_main_queue(), ^{
                //设置界面的按钮显示 根据自己需求设置
                [verifybutton setTitle:@"获取验证码" forState:UIControlStateNormal];
                verifybutton.enabled = YES;
                self.inputPhoneNumView.verifyBtn.userInteractionEnabled = YES;
            });
        } else {
            int seconds = time % 60;
            dispatch_async(dispatch_get_main_queue(), ^{
                //设置界面的按钮显示 根据自己需求设置
                [self.inputPhoneNumView.verifyBtn setTitle:[NSString stringWithFormat:@"%2ds后重试", seconds] forState:UIControlStateNormal];
                self.inputPhoneNumView.verifyBtn.userInteractionEnabled = NO;
            });
            time--;
        }
    });
    dispatch_resume(_timer);
}

- (BOOL)IsPhoneNumber:(NSString *)number {
    NSString *phoneRegex = @"1[3-9]\\d{9}";
    NSPredicate *phoneTest = [NSPredicate predicateWithFormat:@"SELF MATCHES %@", phoneRegex];
    return [phoneTest evaluateWithObject:number];
}

- (BOOL)IsVerificationCode:(NSString *)code {
    NSString *codeRegex = @"\\d{6}";
    NSPredicate *codeTest = [NSPredicate predicateWithFormat:@"SELF MATCHES %@", codeRegex];
    return [codeTest evaluateWithObject:code];
}


