#import "WBSubChatMessageCell.h"

#define kAvatarSize 42
#define kAvatarMargin 10
#define kBubbleMarginHorizontal 16
#define kBubbleMarginVertical 12
#define kBubbleCornerRadius 16
#define kMaxBubbleWidth 312

@interface WBSubChatMessageCell ()

@property (nonatomic, strong) UIImageView *avatarView;
@property (nonatomic, strong) UILabel *messageLabel;
@property (nonatomic, strong) UIView *bubbleView;

@end

@implementation WBSubChatMessageCell

- (instancetype)initWithStyle:(UITableViewCellStyle)style reuseIdentifier:(NSString *)reuseIdentifier {
    self = [super initWithStyle:style reuseIdentifier:reuseIdentifier];
    if (self) {
        self.selectionStyle = UITableViewCellSelectionStyleNone;
        self.backgroundColor = [UIColor clearColor];

        // 头像
        _avatarView = [[UIImageView alloc] init];
        _avatarView.layer.cornerRadius = kAvatarSize / 2;
        _avatarView.layer.masksToBounds = YES;
        _avatarView.contentMode = UIViewContentModeScaleAspectFill;
        [self.contentView addSubview:_avatarView];

        // 气泡视图
        _bubbleView = [[UIView alloc] init];
        _bubbleView.layer.cornerRadius = kBubbleCornerRadius;
        [self.contentView addSubview:_bubbleView];

        // 消息内容
        _messageLabel = [[UILabel alloc] init];
        _messageLabel.numberOfLines = 0;
        _messageLabel.font = WBPrimaryFont(16);
        [_bubbleView addSubview:_messageLabel];
    }
    return self;
}

// 消息样式
- (void)configureWithMessage:(WBSubMessageModel *)message {
    if (message.attributedContent) {
        _messageLabel.attributedText = message.attributedContent;
    } else {
        _messageLabel.text = message.content;
    }

    if (message.isSender) {
        _avatarView.image = [UIImage imageNamed:@"subTalk_avatar"];
        _bubbleView.backgroundColor = WBColorHex(0x68ACE3);
        if (!message.attributedContent) {
            _messageLabel.textColor = [UIColor whiteColor];
        }
    } else {
        _avatarView.image = [UIImage imageNamed:@"subMine_AI"];
        _bubbleView.backgroundColor = [UIColor whiteColor];
        if (!message.attributedContent) {
            _messageLabel.textColor = [UIColor blackColor];
        }
    }

    // 计算文本高度
    CGSize maxSize = CGSizeMake(kMaxBubbleWidth - kBubbleMarginHorizontal * 2, CGFLOAT_MAX);
    NSMutableParagraphStyle *paragraphStyle = [[NSMutableParagraphStyle alloc] init];
    paragraphStyle.lineBreakMode = NSLineBreakByWordWrapping; // 按词换行
    CGRect textRect;
    if (message.attributedContent) {
        NSMutableAttributedString *attr = [message.attributedContent mutableCopy];
        [attr addAttribute:NSParagraphStyleAttributeName value:paragraphStyle range:NSMakeRange(0, attr.length)];
        textRect = [attr boundingRectWithSize:maxSize options:NSStringDrawingUsesLineFragmentOrigin | NSStringDrawingUsesFontLeading context:nil];
    } else {
        NSDictionary *attributes = @{ NSFontAttributeName: _messageLabel.font, NSParagraphStyleAttributeName: paragraphStyle };
        textRect = [message.content boundingRectWithSize:maxSize options:NSStringDrawingUsesLineFragmentOrigin | NSStringDrawingUsesFontLeading attributes:attributes context:nil];
    }
    CGSize textSize = CGSizeMake(ceil(textRect.size.width), ceil(textRect.size.height)); // 向上取整

    // 高度补偿（解决中文单行高度偏差）
    if (textSize.height <= _messageLabel.font.lineHeight * 1.5) { // 单行文本判断
        textSize.height = _messageLabel.font.lineHeight; // 强制使用字体行高
    }

    CGFloat bubbleWidth = textSize.width + kBubbleMarginHorizontal * 2;
    CGFloat bubbleHeight = textSize.height + kBubbleMarginVertical * 2;

    CGRect avatarFrame, bubbleFrame;
    if (message.isSender) {
        avatarFrame = CGRectMake(CGRectGetWidth(self.contentView.frame) - kAvatarSize - kBubbleMarginHorizontal,
                                kBubbleMarginVertical,
                                kAvatarSize,
                                kAvatarSize);
        bubbleFrame = CGRectMake(CGRectGetMinX(avatarFrame) - kBubbleMarginHorizontal - bubbleWidth,
                                 kBubbleMarginVertical,
                                 bubbleWidth,
                                 bubbleHeight);
    } else {
        avatarFrame = CGRectMake(kBubbleMarginHorizontal,
                                 kBubbleMarginVertical,
                                 kAvatarSize,
                                 kAvatarSize);
        bubbleFrame = CGRectMake(CGRectGetMaxX(avatarFrame) + kBubbleMarginHorizontal,
                                 kBubbleMarginVertical,
                                 bubbleWidth,
                                 bubbleHeight);
    }

    _avatarView.frame = avatarFrame;
    _bubbleView.frame = bubbleFrame;
    _messageLabel.frame = CGRectMake(kBubbleMarginHorizontal,
                                     kBubbleMarginVertical,
                                     textSize.width,
                                     textSize.height);

    // 加载动画
    if ([message.content isEqualToString:@"思考中..."]) {
        CABasicAnimation *pulse = [CABasicAnimation animationWithKeyPath:@"opacity"];
        pulse.duration = 1.0;
        pulse.fromValue = @(0.5);
        pulse.toValue = @(1.0);
        pulse.autoreverses = YES;
        pulse.repeatCount = HUGE_VALF;
        [_messageLabel.layer addAnimation:pulse forKey:@"pulseAnimation"];
    } else {
        [_messageLabel.layer removeAllAnimations];
    }
}

// 高度计算
+ (CGFloat)heightForMessage:(WBSubMessageModel *)message withWidth:(CGFloat)width {
    UIFont *font = WBPrimaryFont(16);
    CGSize maxSize = CGSizeMake(kMaxBubbleWidth - kBubbleMarginHorizontal * 2, CGFLOAT_MAX);

    NSMutableParagraphStyle *style = [[NSMutableParagraphStyle alloc] init];
    style.lineBreakMode = NSLineBreakByWordWrapping;
    CGRect textRect;
    if (message.attributedContent) {
        NSMutableAttributedString *attr = [message.attributedContent mutableCopy];
        [attr addAttribute:NSParagraphStyleAttributeName value:style range:NSMakeRange(0, attr.length)];
        textRect = [attr boundingRectWithSize:maxSize options:NSStringDrawingUsesLineFragmentOrigin | NSStringDrawingUsesFontLeading context:nil];
    } else {
        textRect = [message.content boundingRectWithSize:maxSize options:NSStringDrawingUsesLineFragmentOrigin | NSStringDrawingUsesFontLeading attributes:@{NSFontAttributeName: font, NSParagraphStyleAttributeName: style} context:nil];
    }
    CGFloat textHeight = ceil(textRect.size.height);

    // 单行文本高度补偿
    if (textHeight <= font.lineHeight * 1.5) {
        textHeight = font.lineHeight;
    }

    CGFloat bubbleHeight = textHeight + kBubbleMarginVertical * 3.3;
    CGFloat avatarHeight = kAvatarSize + kBubbleMarginVertical * 1.4;
    return MAX(bubbleHeight, avatarHeight) + ZOOM(4);
}

- (UIView *)bubbleContainerView {
    return _bubbleView;
}

@end


